CREATE TABLE logs (
  log_id     INT PRIMARY KEY,
  log_level  VARCHAR(10),
  message    VARCHAR(200),
  created_at TIMESTAMP
);

INSERT INTO logs VALUES
  (1,  'INFO',  'User logged in',           '2026-01-01 08:00:00'),
  (2,  'DEBUG', 'Query executed in 5ms',     '2026-01-01 08:01:00'),
  (3,  'ERROR', 'Connection timeout',        '2026-01-01 08:05:00'),
  (4,  'INFO',  'File uploaded',             '2026-01-02 09:00:00'),
  (5,  'DEBUG', 'Cache miss for key:user_5', '2026-01-02 09:01:00'),
  (6,  'WARN',  'High memory usage 85%',     '2026-01-02 10:00:00'),
  (7,  'DEBUG', 'SQL query plan computed',   '2026-01-03 11:00:00'),
  (8,  'INFO',  'Report generated',          '2026-01-03 11:30:00'),
  (9,  'ERROR', 'Disk space critical',       '2026-01-03 12:00:00'),
  (10, 'INFO',  'Backup completed',          '2026-01-04 02:00:00');

SELECT log_level, COUNT(*) AS count FROM logs GROUP BY log_level;

-- Delete all DEBUG logs (verbose, not needed for archiving)
DELETE FROM logs WHERE log_level = 'DEBUG';

-- Delete old INFO logs older than Jan 3
DELETE FROM logs
WHERE log_level = 'INFO' AND created_at < '2026-01-03 00:00:00';

-- Verify remaining logs
SELECT * FROM logs ORDER BY created_at;
SELECT log_level, COUNT(*) AS count FROM logs GROUP BY log_level ORDER BY count DESC;
